    const layoutMigrationSource = `
function moveLayoutItemToEnd(iids, iid) {
    if (!Array.isArray(iids) || !iid) return;
    const index = iids.indexOf(iid);
    if (index < 0 || index === iids.length - 1) return;
    const [item] = iids.splice(index, 1);
    iids.push(item);
}

function migrateFirstPageMusicToBottom(savedLayouts) {
    const pageLayout = Array.isArray(savedLayouts)
        ? savedLayouts.find(layoutData => layoutData && layoutData.cid === 'page-1' && Array.isArray(layoutData.iids))
        : null;
    if (!pageLayout) return;
    moveLayoutItemToEnd(pageLayout.iids, 'panel-music-player');
}

function migrateSecondPageAvatarDefaultLayout(savedLayouts) {
    const pageLayout = Array.isArray(savedLayouts)
        ? savedLayouts.find(layoutData => layoutData && layoutData.cid === 'page-2' && Array.isArray(layoutData.iids))
        : null;
    if (!pageLayout) return;

    const iids = pageLayout.iids;
    const oldDefaultIndex = iids.findIndex((iid, index) =>
        iid === 'panel-dreamy-card' &&
        iids[index + 1] === 'grid-page-2-1-block' &&
        iids[index + 2] === 'panel-dual-avatar' &&
        iids[index + 3] === 'panel-sun-card' &&
        iids[index + 4] === 'grid-page-2-2-block'
    );
    if (oldDefaultIndex < 0) return;

    const dualIndex = oldDefaultIndex + 2;
    const sunIndex = oldDefaultIndex + 3;
    [iids[dualIndex], iids[sunIndex]] = [iids[sunIndex], iids[dualIndex]];
}

if (typeof layoutUsesLegacyIds === 'function' && !layoutUsesLegacyIds.__rinnoDesktopHomeOrderFix) {
    const baseLayoutUsesLegacyIds = layoutUsesLegacyIds;
    layoutUsesLegacyIds = function(savedLayouts) {
        migrateFirstPageMusicToBottom(savedLayouts);
        migrateSecondPageAvatarDefaultLayout(savedLayouts);
        return baseLayoutUsesLegacyIds(savedLayouts);
    };
    layoutUsesLegacyIds.__rinnoDesktopHomeOrderFix = true;
}
`;

    const delegatedAppLauncherSource = `
function openDelegatedRinnoApp(name) {
    const lock = document.getElementById('lock-screen');
    if (lock && !lock.classList.contains('unlocked')) return false;
    const launchers = {
        letter: typeof openLetterApp === 'function' ? openLetterApp : null,
        settings: typeof openSettingsApp === 'function' ? openSettingsApp : null,
        style: typeof openStyleApp === 'function' ? openStyleApp : null,
        private: typeof openPrivateApp === 'function' ? openPrivateApp : null,
        prologue: typeof openPrologueApp === 'function' ? openPrologueApp : null,
        community: typeof openCommunityApp === 'function' ? openCommunityApp : null,
        encounter: typeof openEncounterApp === 'function' ? openEncounterApp : null,
        dossier: typeof openDossierApp === 'function' ? openDossierApp : null,
        wanye: typeof openWanyeApp === 'function' ? openWanyeApp : null,
        lingguang: typeof openLingguangApp === 'function' ? openLingguangApp : null,
        guide: typeof openGuideApp === 'function' ? openGuideApp : null,
        zhenxuan: typeof openZhenxuanApp === 'function' ? openZhenxuanApp : null,
        phone: typeof openPhoneApp === 'function' ? openPhoneApp : null,
        assets: typeof openAssetsApp === 'function' ? openAssetsApp : null,
        trace: typeof openTraceApp === 'function' ? openTraceApp : null,
        cinema: typeof openCinemaApp === 'function' ? openCinemaApp : null
    };
    const launcher = launchers[name] || null;
    if (typeof launcher !== 'function') return false;
    launcher();
    return true;
}

function isDelegatedRinnoAppLaunchSuppressed() {
    const now = window.performance && typeof window.performance.now === 'function'
        ? window.performance.now()
        : Date.now();
    return now < (Number(window.__rinnoSuppressAppLaunchUntil) || 0);
}

document.addEventListener('click', function(event) {
    if (document.body.classList.contains('edit-mode')) return;
    if (isDelegatedRinnoAppLaunchSuppressed()) {
        event.preventDefault();
        event.stopImmediatePropagation();
        return;
    }
    const target = event.target instanceof Element ? event.target : event.target?.parentElement;
    if (target && document.getElementById('app-root')?.contains(target)) return;
    const launcher = target?.closest?.('[data-open-app]');
    if (!launcher || !document.body.contains(launcher)) return;
    if (openDelegatedRinnoApp(launcher.getAttribute('data-open-app') || '')) {
        event.preventDefault();
        event.stopPropagation();
    }
});
`;

    const desktopDockSafetyLockSource = `
(function() {
    if (window.__rinnoDesktopDockSafetyLockInstalled) return;
    window.__rinnoDesktopDockSafetyLockInstalled = true;

    const DESKTOP_LOCK_TOAST_ID = 'rinno-desktop-lock-toast';
    const DESKTOP_LOCK_STYLE_ID = 'rinno-desktop-lock-toast-style';
    let desktopLockToastTimer = 0;

    function ensureDesktopLockToastStyle() {
        if (document.getElementById(DESKTOP_LOCK_STYLE_ID)) return;
        const style = document.createElement('style');
        style.id = DESKTOP_LOCK_STYLE_ID;
        style.textContent = [
            '#' + DESKTOP_LOCK_TOAST_ID + ' {',
            'position: fixed;',
            'left: 50%;',
            'top: calc(env(safe-area-inset-top, 0px) + 14px);',
            'transform: translate(-50%, -10px) scale(0.98);',
            'padding: 9px 15px;',
            'border-radius: 999px;',
            'font-size: 12px;',
            'font-weight: 600;',
            'letter-spacing: 0.2px;',
            'line-height: 1;',
            'white-space: nowrap;',
            'color: rgba(47, 39, 44, 0.92);',
            'background: rgba(255, 255, 255, 0.96);',
            'border: 1px solid rgba(150, 124, 136, 0.26);',
            'box-shadow: 0 12px 28px rgba(67, 47, 58, 0.16);',
            'opacity: 0;',
            'pointer-events: none;',
            'z-index: 1000000;',
            'transition: opacity 0.2s ease, transform 0.2s ease;',
            '}',
            '#' + DESKTOP_LOCK_TOAST_ID + '.show {',
            'opacity: 1;',
            'transform: translate(-50%, 0) scale(1);',
            '}'
        ].join('');
        document.head.appendChild(style);
    }

    function showDesktopLockToast(message) {
        ensureDesktopLockToastStyle();
        let toast = document.getElementById(DESKTOP_LOCK_TOAST_ID);
        if (!toast) {
            toast = document.createElement('div');
            toast.id = DESKTOP_LOCK_TOAST_ID;
            toast.setAttribute('role', 'status');
            toast.setAttribute('aria-live', 'polite');
            document.body.appendChild(toast);
        }
        toast.textContent = String(message || '\u6ca1\u6709\u7a7a\u95f2\u7684\u4f4d\u7f6e\u4e86\u634f~');
        toast.classList.add('show');
        window.clearTimeout(desktopLockToastTimer);
        desktopLockToastTimer = window.setTimeout(() => {
            toast.classList.remove('show');
        }, 1500);
    }

    function getDesktopDockTopBoundary() {
        const dock = document.querySelector('.dock');
        if (!dock) return window.innerHeight || document.documentElement.clientHeight || 0;
        const rect = dock.getBoundingClientRect();
        return Math.max(0, rect.top - 6);
    }

    function isDesktopPageNode(node) {
        return Boolean(
            node &&
            node.parentElement &&
            node.parentElement.id === 'slider' &&
            node.classList &&
            node.classList.contains('page')
        );
    }

    function getActiveDesktopPageForLock() {
        const pages = typeof getDesktopPages === 'function'
            ? getDesktopPages()
            : Array.from(document.querySelectorAll('#slider > .page'));
        if (!pages.length) return null;
        const activeIndex = Number(typeof currentPage === 'number' ? currentPage : 0);
        return pages[activeIndex] || pages[0] || null;
    }

    function isPagePastDockBoundary(page) {
        if (!isDesktopPageNode(page)) return false;
        const limit = getDesktopDockTopBoundary();
        const candidates = Array.from(page.children).filter(node => {
            if (!(node instanceof HTMLElement)) return false;
            if (node.classList.contains('status-bar')) return false;
            if (node.classList.contains('dock')) return false;
            if (node.classList.contains('pagination')) return false;
            if (node.classList.contains('search-pill')) return false;
            const style = getComputedStyle(node);
            if (style.display === 'none' || style.visibility === 'hidden' || Number(style.opacity) === 0) return false;
            return true;
        });
        return candidates.some(node => {
            const rect = node.getBoundingClientRect();
            if (rect.width <= 1 || rect.height <= 1) return false;
            return rect.bottom > limit;
        });
    }

    function getSelectorSafeValue(value) {
        const raw = String(value || '');
        if (typeof CSS !== 'undefined' && typeof CSS.escape === 'function') return CSS.escape(raw);
        return raw.replace(/["\\\\]/g, '\\\\$&');
    }

    function snapshotDesktopAppLayout() {
        return Array.from(document.querySelectorAll('.app-wrapper[data-iid]')).map(node => {
            const parent = node.parentElement;
            let next = node.nextElementSibling;
            while (next && !(next.classList?.contains('app-wrapper') && next.hasAttribute('data-iid'))) {
                next = next.nextElementSibling;
            }
            return {
                iid: String(node.getAttribute('data-iid') || ''),
                parentCid: String(parent?.getAttribute('data-cid') || ''),
                nextIid: String(next?.getAttribute('data-iid') || '')
            };
        }).filter(record => record.iid && record.parentCid);
    }

    function restoreDesktopAppLayout(snapshot) {
        if (!Array.isArray(snapshot) || !snapshot.length) return;
        snapshot.forEach(record => {
            const node = document.querySelector('.app-wrapper[data-iid="' + getSelectorSafeValue(record.iid) + '"]');
            const parent = document.querySelector('[data-cid="' + getSelectorSafeValue(record.parentCid) + '"]');
            if (!node || !parent) return;
            if (record.nextIid) {
                const next = parent.querySelector(':scope > .app-wrapper[data-iid="' + getSelectorSafeValue(record.nextIid) + '"]');
                if (next) {
                    parent.insertBefore(node, next);
                    return;
                }
            }
            parent.appendChild(node);
        });
    }

    function patchArrangeEndWithDockSafetyLock() {
        const original = typeof endArrange === 'function' ? endArrange : null;
        if (typeof original !== 'function' || original.__rinnoDesktopDockSafetyLockPatched) return;

        const wrapped = function(event) {
            const draggingAppIcon = Boolean(
                (typeof draggedNode !== 'undefined' && draggedNode) &&
                draggedNode.classList &&
                draggedNode.classList.contains('app-wrapper')
            );
            const shouldGuard = Boolean(draggingAppIcon && (typeof ghostNode !== 'undefined' && ghostNode));
            const snapshot = shouldGuard ? snapshotDesktopAppLayout() : null;
            const activePageBefore = shouldGuard ? getActiveDesktopPageForLock() : null;

            original.call(this, event);

            if (!snapshot || !activePageBefore) return;
            const activePageAfter = getActiveDesktopPageForLock() || activePageBefore;
            if (!isPagePastDockBoundary(activePageAfter)) return;

            restoreDesktopAppLayout(snapshot);
            if (typeof normalizeFreeIconGrids === 'function') normalizeFreeIconGrids();
            if (typeof enforceDockIconLimit === 'function') enforceDockIconLimit();
            if (typeof purgeEmptyFreeIconGrids === 'function') purgeEmptyFreeIconGrids();
            if (typeof checkEmptyPages === 'function') checkEmptyPages();
            if (typeof saveCurrentLayout === 'function') saveCurrentLayout();
            showDesktopLockToast('\u6ca1\u6709\u7a7a\u95f2\u7684\u4f4d\u7f6e\u4e86\u634f~');
        };

        wrapped.__rinnoDesktopDockSafetyLockPatched = true;
        original.__rinnoDesktopDockSafetyLockPatched = true;

        document.removeEventListener('touchend', original);
        document.removeEventListener('touchcancel', original);
        document.removeEventListener('mouseup', original);

        document.addEventListener('touchend', wrapped);
        document.addEventListener('touchcancel', wrapped);
        document.addEventListener('mouseup', wrapped);

        window.endArrange = wrapped;
    }

    patchArrangeEndWithDockSafetyLock();
})();
`;

    function stripDevServerInjection(text) {
        return String(text)
            .replace(/<!-- Code injected by live-server -->\s*<script\b[^>]*>[\s\S]*?<\/script>/g, '')
            .replace(/<script\b[^>]*>[\s\S]*?(?:refreshCSS|Live reload enabled|Live-Reloading)[\s\S]*?<\/script>/g, '')
            .replace(/<!-- Code injected by live-server -->\s*<script\b[^>]*>[\s\S]*$/g, '')
            .replace(/<script\b[^>]*>[\s\S]*?(?:refreshCSS|Live reload enabled|Live-Reloading)[\s\S]*$/g, '');
    }

